const items = $input.all();
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

let nuevos = 0, contactados = 0, pendientes = 0, inactivos = 0, citasAgendadas = 0;

for (const item of items) {
  const row = item.json;
  if (!row.Numero) continue;
  const fecha = new Date(row.Fecha || row.ultima_interaccion || 0);
  const estado = (row.estado || 'nuevo').toLowerCase();
  if (fecha >= weekAgo) nuevos++;
  if (estado === 'contactado') contactados++;
  if (estado === 'pendiente') pendientes++;
  if (estado === 'inactivo') inactivos++;
  if (estado === 'cita_agendada') citasAgendadas++;
}

const fechaInicio = weekAgo.toLocaleDateString('es-ES', { day: '2-digit', month: '2-digit' });
const fechaFin = now.toLocaleDateString('es-ES', { day: '2-digit', month: '2-digit' });

const mensaje = `📊 *Reporte Semanal*\n_${fechaInicio} — ${fechaFin}_\n\n🆕 Leads nuevos: ${nuevos}\n✅ Contactados: ${contactados}\n⏳ Pendientes: ${pendientes}\n💤 Inactivos: ${inactivos}\n📅 Citas agendadas: ${citasAgendadas}\n\n_Generado automáticamente por Geor_ 🤖`;

return [{ json: { mensaje, nuevos, contactados, pendientes, inactivos, citasAgendadas } }];

const items = $input.all();
const now = new Date();
const cutoff48h = new Date(now.getTime() - 48 * 60 * 60 * 1000);

const parseDate = (str) => {
  if (!str) return new Date(0);
  const parts = str.split('/');
  if (parts.length === 3) return new Date(parts[2], parts[1]-1, parts[0]);
  return new Date(str);
};

const inactivos = items.filter(item => {
  const row = item.json;
  if (!row.Numero) return false;
  const estado = (row.estado || 'nuevo').toLowerCase();
  const ultimaInteraccion = parseDate(row.ultima_interaccion || row.Fecha);
  if (['inactivo', 'cita_agendada', 'cerrado'].includes(estado)) return false;
  return ultimaInteraccion < cutoff48h;
});

if (inactivos.length === 0) return [{ json: { sinInactivos: true, total: 0 } }];

return inactivos.map(item => ({
  json: {
    ...item.json,
    sinInactivos: false,
    numero: String(item.json.Numero || '').replace(/=/g, '').replace('@s.whatsapp.net', '')
  }
}));

const output = $input.first().json.output || '';
const remoteJid = $('Webhook').first().json.body.data.key.remoteJid;

const citaMatch = output.includes('[[CITA_SOLICITADA]]');
const llamadaMatch = output.includes('[[LLAMADA_SOLICITADA]]');

let nombreCita = 'Cliente', fechaCita = '', horaCita = '';
const citaDataMatch = output.match(/\[\[CITA_SOLICITADA\]\]\s*(\{[\s\S]*?\})/);
if (citaDataMatch) {
  try {
    const data = JSON.parse(citaDataMatch[1]);
    nombreCita = data.nombre || 'Cliente';
    fechaCita = data.fecha || '';
    horaCita = data.hora || '';
  } catch(e) {}
}

let nombreLlamada = 'Cliente';
const llamadaDataMatch = output.match(/\[\[LLAMADA_SOLICITADA\]\]\s*(\{[\s\S]*?\})/);
if (llamadaDataMatch) {
  try {
    const data = JSON.parse(llamadaDataMatch[1]);
    nombreLlamada = data.nombre || 'Cliente';
  } catch(e) {}
}

const cleanOutput = output
  .replace(/\[\[CITA_SOLICITADA\]\][\s\S]*?\{[\s\S]*?\}/g, '')
  .replace(/\[\[LLAMADA_SOLICITADA\]\][\s\S]*?\{[\s\S]*?\}/g, '')
  .replace('[[CITA_SOLICITADA]]', '')
  .replace('[[LLAMADA_SOLICITADA]]', '')
  .trim();

const ahora = new Date();
const hora = ahora.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Atlantic/Canary' });
const fecha = ahora.toLocaleDateString('es-ES', { day: '2-digit', month: '2-digit', year: 'numeric', timeZone: 'Atlantic/Canary' });

return [{
  json: {
    output: cleanOutput,
    citaSolicitada: citaMatch,
    llamadaSolicitada: llamadaMatch,
    nombreCita, fechaCita, horaCita, nombreLlamada,
    remoteJid,
    numero: remoteJid.split('@')[0],
    numeroLimpio: remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', ''),
    horaContacto: hora,
    fechaContacto: fecha
  }
}];

const payload = $input.item.json.body.payload;
const nombre = payload.name || '';
const email = payload.email || '';
const preguntas = payload.questions_and_answers || [];
let telefono = '', negocio = '';
for (const q of preguntas) {
  const pregunta = q.question.toLowerCase();
  if (pregunta.includes('whatsapp') || pregunta.includes('teléfono')) telefono = q.answer.replace(/[^0-9]/g, '');
  if (pregunta.includes('negocio')) negocio = q.answer;
}
return [{ json: { nombre, email, telefono, negocio, fechaCita: payload.event?.start_time || '' } }];
